import React from 'react';
import config from '../config';
import './Cart.css';

/**
 * Cart Component
 * Pure UI component — NO state mutation here
 */
const Cart = ({ items, onUpdateQuantity, onRemoveItem, onCheckout }) => {

  const calculateSubtotal = () => {
    return items.reduce(
      (total, item) => total + item.price * item.quantity,
      0
    );
  };

  const formatCurrency = (amount) => {
    return `${config.CURRENCY_SYMBOL}${amount.toFixed(2)}`;
  };

  if (!items || items.length === 0) {
    return (
      <div className="cart cart-empty">
        <div className="empty-cart-icon">🛒</div>
        <h3>Your cart is empty</h3>
        <p>Scan a barcode to add items</p>
      </div>
    );
  }

  const subtotal = calculateSubtotal();

  return (
    <div className="cart">
      <div className="cart-header">
        <h3>
          Cart ({items.length} {items.length === 1 ? 'item' : 'items'})
        </h3>
      </div>

      <div className="cart-items">
        {items.map((item) => (
          <div key={item.sku} className="cart-item">
            <div className="cart-item-info">
              <h4 className="cart-item-name">{item.name}</h4>
              <p className="cart-item-sku">SKU: {item.sku}</p>
              <p className="cart-item-price">
                {formatCurrency(item.price)} each
              </p>
            </div>

            <div className="cart-item-controls">
              <div className="quantity-control">
                <button
                  className="qty-btn"
                  disabled={item.quantity <= 1}
                  onClick={() =>
                    onUpdateQuantity(item.sku, item.quantity - 1)
                  }
                >
                  −
                </button>

                <span className="qty-display">{item.quantity}</span>

                <button
                  className="qty-btn"
                  onClick={() =>
                    onUpdateQuantity(item.sku, item.quantity + 1)
                  }
                >
                  +
                </button>
              </div>

              <div className="cart-item-total">
                {formatCurrency(item.price * item.quantity)}
              </div>

              <button
                className="remove-btn"
                title="Remove item"
                onClick={() => onRemoveItem(item.sku)}
              >
                🗑️
              </button>
            </div>
          </div>
        ))}
      </div>

      <div className="cart-summary">
        <div className="cart-subtotal">
          <span>Subtotal:</span>
          <span>{formatCurrency(subtotal)}</span>
        </div>

        <p className="discount-note">
          💡 Discount will be applied at checkout
        </p>

        <button
          onClick={onCheckout}
          className="btn btn-primary btn-large btn-checkout"
        >
          Proceed to Checkout →
        </button>
      </div>
    </div>
  );
};

export default Cart;
